-- Mỗi rạp 4 phòng
INSERT INTO rooms (theater_id, name, type, total_seats, status, storage_state)
SELECT t.id, N'Phòng 1 - IMAX',  N'IMAX',    96, N'ACTIVE', N'ACTIVE' FROM theaters t WHERE t.code LIKE N'CNX-%';

INSERT INTO rooms (theater_id, name, type, total_seats, status, storage_state)
SELECT t.id, N'Phòng 2 - 3D',    N'THREE_D', 96, N'ACTIVE', N'ACTIVE' FROM theaters t WHERE t.code LIKE N'CNX-%';

INSERT INTO rooms (theater_id, name, type, total_seats, status, storage_state)
SELECT t.id, N'Phòng 3',         N'TWO_D',   96, N'ACTIVE', N'ACTIVE' FROM theaters t WHERE t.code LIKE N'CNX-%';

INSERT INTO rooms (theater_id, name, type, total_seats, status, storage_state)
SELECT t.id, N'Phòng 4',         N'TWO_D',   96, N'ACTIVE', N'ACTIVE' FROM theaters t WHERE t.code LIKE N'CNX-%';

-- Sinh 96 ghế cho mỗi phòng: 8 hàng A-H × 12 cột 1-12
-- A-F (6 hàng × 12) = 72 STANDARD
-- G (1 hàng × 12) = 12 VIP
-- H (1 hàng × 12) = 12 COUPLE (mỗi 2 ghế liền = 1 cặp)

DECLARE @row_idx INT, @col_idx INT;
DECLARE @row_label NVARCHAR(2), @seat_type NVARCHAR(20);

DECLARE room_cursor CURSOR FOR SELECT id FROM rooms;
DECLARE @room_id BIGINT;
OPEN room_cursor;
FETCH NEXT FROM room_cursor INTO @room_id;
WHILE @@FETCH_STATUS = 0
BEGIN
    SET @row_idx = 1;
    WHILE @row_idx <= 8
    BEGIN
        SET @row_label = CHAR(64 + @row_idx);  -- A=65 → 'A'
        IF @row_idx <= 6 SET @seat_type = N'STANDARD';
        ELSE IF @row_idx = 7 SET @seat_type = N'VIP';
        ELSE SET @seat_type = N'COUPLE';

        SET @col_idx = 1;
        WHILE @col_idx <= 12
        BEGIN
            INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, storage_state)
            VALUES (@room_id, @row_label, @col_idx, @row_label + CAST(@col_idx AS NVARCHAR(2)), @seat_type, N'AVAILABLE', N'ACTIVE');
            SET @col_idx = @col_idx + 1;
        END
        SET @row_idx = @row_idx + 1;
    END
    FETCH NEXT FROM room_cursor INTO @room_id;
END
CLOSE room_cursor;
DEALLOCATE room_cursor;
